import java.util.ArrayList;
import java.util.List;

public List<Boolean> prefixesDivBy5(int[] nums) {
    List<Boolean> result = new ArrayList<>();
    int current = 0;
    for (int num : nums) {
        current = ((current << 1) | num) % 5;
        result.add(current == 0);
    }
    return result;
}
```

